@RestController
class AuthController {
    static final String SESSION_USER = "OIDC_USER";
    static final String SESSION_ACCESS_TOKEN = "OIDC_ACCESS_TOKEN";

    private final OidcClient oidcClient;
    private final OidcStateStore stateStore;
    private final OidcProperties props;

    AuthController(OidcClient oidcClient, OidcStateStore stateStore, OidcProperties props) {
        this.oidcClient = oidcClient;
        this.stateStore = stateStore;
        this.props = props;
    }

    @GetMapping("/auth/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String nonce = randomUrlSafe(24);
        String state = stateStore.createState(nonce);

        request.getSession(true).setAttribute("OIDC_STATE", state);

        String url = oidcClient.buildAuthorizationRequestUrl(state, nonce);
        response.sendRedirect(url);
    }

    @GetMapping("/auth/callback")
    public void callback(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String err = request.getParameter("error");
        String errDesc = request.getParameter("error_description");

        if (err != null) {
            response.setStatus(401);
            response.setContentType("text/plain");
            response.getWriter().write("OIDC error: " + err + (errDesc != null ? " - " + errDesc : ""));
            return;
        }

        if (code == null || state == null) {
            response.setStatus(400);
            response.setContentType("text/plain");
            response.getWriter().write("Missing code/state");
            return;
        }

        HttpSession session = request.getSession(true);
        String expectedState = (String) session.getAttribute("OIDC_STATE");
        session.removeAttribute("OIDC_STATE");
        if (expectedState == null || !expectedState.equals(state)) {
            response.setStatus(401);
            response.setContentType("text/plain");
            response.getWriter().write("Invalid state");
            return;
        }

        String nonce = stateStore.consumeNonce(state).orElse(null);

        TokenResponse tokenResponse = oidcClient.exchangeCodeForTokens(code);
        OidcUserSession userSession = oidcClient.parseAndValidateIdToken(tokenResponse.id_token(), nonce);

        String accessToken = tokenResponse.access_token();
        if (accessToken != null && !accessToken.isBlank()) {
            userSession = new OidcUserSession(
                    userSession.subject(),
                    userSession.email(),
                    userSession.name(),
                    userSession.preferredUsername(),
                    userSession.issuer(),
                    userSession.audience(),
                    userSession.issuedAt(),
                    userSession.expiresAt(),
                    userSession.claims(),
                    accessToken
            );
            session.setAttribute(SESSION_ACCESS_TOKEN, accessToken);
        }

        session.setAttribute(SESSION_USER, userSession);

        response.sendRedirect(props.postLoginRedirect);
    }

    @GetMapping("/auth/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();

        Cookie jsession = new Cookie("JSESSIONID", "");
        jsession.setPath("/");
        jsession.setMaxAge(0);
        response.addCookie(jsession);

        response.sendRedirect("/");
    }

    @GetMapping("/me")
    public Map<String, Object> me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return Map.of("authenticated", false);

        OidcUserSession user = (OidcUserSession) session.getAttribute(SESSION_USER);
        if (user == null) return Map.of("authenticated", false);

        return Map.of(
                "authenticated", true,
                "sub", user.subject(),
                "email", user.email(),
                "name", user.name(),
                "preferred_username", user.preferredUsername(),
                "issuer", user.issuer(),
                "audience", user.audience(),
                "issued_at", user.issuedAt() == null ? null : user.issuedAt().toString(),
                "expires_at", user.expiresAt() == null ? null : user.expiresAt().toString(),
                "claims", user.claims()
        );
    }

    @GetMapping("/userinfo")
    public Map<String, Object> userinfo(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) throw new UnauthorizedException();

        String accessToken = (String) session.getAttribute(SESSION_ACCESS_TOKEN);
        if (accessToken == null || accessToken.isBlank()) throw new UnauthorizedException();

        return oidcClient.fetchUserInfo(accessToken);
    }

    private static String randomUrlSafe(int bytes) {
        byte[] b = new byte[bytes];
        new SecureRandom().nextBytes(b);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(b);
    }
}

@Component
class OidcAuthenticationFilter extends OncePerRequestFilter {
    private static final List<String> PUBLIC_PATH_PREFIXES = List.of(
            "/auth/login",
            "/auth/callback",
            "/auth/logout",
            "/error",
            "/css/",
            "/js/",
            "/images/",
            "/webjars/"
    );

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String path = request.getRequestURI();
        if (isPublic(path)) {
            filterChain.doFilter(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        boolean authenticated = session != null && session.getAttribute(AuthController.SESSION_USER) != null;

        if (!authenticated) {
            response.sendRedirect("/auth/login");
            return;
        }

        filterChain.doFilter(request, response);
    }

    private boolean isPublic(String path) {
        if (path == null) return true;
        if (path.equals("/") || path.equals("/index.html")) return true;
        for (String p : PUBLIC_PATH_PREFIXES) {
            if (path.equals(p) || path.startsWith(p)) return true;
        }
        return false;
    }
}

class UnauthorizedException extends RuntimeException {}

@RestController
class HomeController {
    @GetMapping("/")
    public String home(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        OidcUserSession user = session == null ? null : (OidcUserSession) session.getAttribute(AuthController.SESSION_USER);
        if (user == null) return "Home (public). Go to /auth/login";
        return "Home (authenticated). Hello " + (user.name() != null ? user.name() : user.subject()) + ". Visit /me or /userinfo";
    }
}

